define i32 @ashr_mul_times_5_div_4_exact_2(i32 %x) {
  %mul = mul nsw i32 %x, 5
  %ashr = ashr exact i32 %mul, 2
  ret i32 %ashr
}

define i32 @lshr_mul_times_3_div_2_exact(i32 %x) {
  %mul = mul nsw i32 %x, 3
  %lshr = lshr exact i32 %mul, 1
  ret i32 %lshr
}

define i32 @lshr_mul_times_3_div_2_no_flags(i32 %0) {
  %mul = mul i32 %0, 3
  %lshr = lshr i32 %mul, 1
  ret i32 %lshr
}

define i32 @mul_times_3_div_2_multiuse_lshr(i32 %x) {
  %mul = mul nuw i32 %x, 3
  %res = lshr i32 %mul, 1
  call void @use(i32 %mul)
  ret i32 %res
}

define i32 @reduce_shift(i32 %x) {
  %mul = mul nsw i32 %x, 12
  %shr = ashr i32 %mul, 4
  ret i32 %shr
}

define i32 @reduce_shift_exact(i32 %x) {
  %mul = mul nsw i32 %x, 12
  %shr = ashr exact i32 %mul, 4
  ret i32 %shr
}

define i32 @reduce_shift_no_nsw(i32 %x) {
  %mul = mul nuw i32 %x, 12
  %shr = ashr i32 %mul, 4
  ret i32 %shr
}

define i32 @reduce_shift_wrong_mul(i32 %x) {
